// 1. PETICIÓN AUTÓNOMA AL ENDPOINT DEL TIMELINE
const response = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://gestiondocente.info.unlp.edu.ar/api/v2/timeline.json',
  json: true
});

// 2. EXTRAER EL CONTENIDO RELEVANTE
const items = response._embedded?.content || [];

// 3. PROCESAR Y LIMPIAR LAS NOTICIAS
const noticiasProcesadas = items.map(item => {
    const data = item._embedded?.noticia;
    if (!data) return null;

    // Formatear la fecha a algo más legible
    const fechaLimpia = data.fecha ? data.fecha.split('T')[0] : "Fecha no disponible";

    // Limpieza profunda de HTML del cuerpo de la noticia
    const cuerpoLimpio = data.cuerpo
        .replace(/<[^>]*>?/gm, ' ') // Quita etiquetas HTML
        .replace(/&bull;/g, '•')     // Convierte viñetas
        .replace(/&nbsp;/g, ' ')    // Quita espacios HTML
        .replace(/&aacute;/g, 'á').replace(/&eacute;/g, 'é').replace(/&iacute;/g, 'í').replace(/&oacute;/g, 'ó').replace(/&uacute;/g, 'ú')
        .replace(/&ntilde;/g, 'ñ').replace(/&iquest;/g, '¿')
        .replace(/\s+/g, ' ')       // Quita espacios múltiples
        .trim();

    // Devolvemos un string compacto por cada noticia
    return `[${fechaLimpia}] TITULO: ${data.titulo}\nRESUMEN: ${cuerpoLimpio.substring(0, 300)}...`;
}).filter(n => n !== null);

// 4. VALIDACIÓN DE RESULTADOS
if (noticiasProcesadas.length === 0) {
    return "No hay noticias o actividades recientes en el timeline en este momento.";
}

// 5. RETORNAR EL STRING PLANO AL AGENTE (Limitado a las últimas 8 noticias para no saturar)
return "NOVEDADES Y ACTIVIDADES RECIENTES DE LA FACULTAD:\n\n" + noticiasProcesadas.slice(0, 8).join('\n\n---\n\n');

// 1. OBTENCIÓN DIRECTA
const slug = query.slug;

// 2. VALIDACIÓN
if (!slug) return "ERROR: No llegó el slug.";

try {
  // 3. LLAMADA A LA API
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://gestiondocente.info.unlp.edu.ar/api/v2/materias/${slug}/mensajes.json`,
    qs: { limit: 5 }, // Traemos solo las últimas 5 para no saturar
    json: true
  });

  // 4. EXTRACCIÓN CORRECTA (Aquí estaba el error antes)
  // La API guarda la lista dentro de response._embedded.mensajes
  const mensajes = response._embedded?.mensajes || [];

  if (mensajes.length === 0) {
    return `ℹ️ No hay novedades recientes publicadas en la cartelera de '${slug}'.`;
  }

  // 5. LIMPIEZA DE HTML (Vital porque la captura muestra mucho HTML sucio)
  const clean = (t) => (t || "")
    .replace(/<br\s*\/?>/gi, '\n') // Convertimos <br> en saltos de línea reales
    .replace(/<[^>]*>?/gm, '')     // Borramos el resto de etiquetas HTML
    .replace(/&nbsp;/g, ' ')       // Quitamos espacios HTML
    .replace(/\s+/g, ' ')          // Colapsamos espacios múltiples
    .trim();

  // 6. FORMATEO DE SALIDA
  const lista = mensajes.map(m => {
    const titulo = clean(m.titulo || m.asunto || "Sin título");
    // Usamos updated_at o created_at según lo que venga
    const fechaRaw = m.updated_at || m.created_at || m.fecha; 
    const fecha = fechaRaw ? fechaRaw.split('T')[0] : "Fecha desc."; 
    const contenido = clean(m.cuerpo || m.mensaje).slice(0, 250); // Un poco más largo para que se entienda

    return `📌 *${titulo}* (${fecha})\n"${contenido}..."`;
  }).join("\n\n-------------------\n\n");

  return `📢 ÚLTIMAS NOVEDADES DE ${slug.toUpperCase()}:\n\n${lista}`;

} catch (error) {
  // Si falla, mostramos el error técnico para depurar mejor
  const errorMsg = error.response?.data ? JSON.stringify(error.response.data) : error.message;
  return `ERROR TÉCNICO: No pude acceder a los mensajes. Detalle: ${errorMsg}`;
}

