// 1. OBTENCIÓN DIRECTA
const slug = query.slug;

// 2. VALIDACIÓN
if (!slug) return "ERROR: No llegó el slug.";

try {
  // 3. LLAMADA A LA API
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://gestiondocente.info.unlp.edu.ar/api/v2/materias/${slug}/reservas.json`,
    json: true
  });

  // 4. ESTRATEGIA DE LECTURA (Soporta formato directo o HATEOAS)
  // Asumimos que si es HATEOAS viene en _embedded.reservas, si no, es el response directo
  const reservas = response._embedded?.reservas || response || [];

  if (!Array.isArray(reservas) || reservas.length === 0) {
    return `ℹ️ No encontré asignaciones de aulas/horarios específicas confirmadas para '${slug}' en este endpoint.`;
  }

  // 5. FORMATEO DE SALIDA
  // Mapeamos campos comunes de reservas (Día, Hora, Aula, Tipo)
  const lista = reservas.map(r => {
    // Intentamos capturar los datos aunque cambien los nombres de los campos
    const dia = r.dia || "Día a confirmar";
    // A veces viene 'hora_inicio', a veces 'inicio'
    const hora = (r.hora_inicio && r.hora_fin) 
                 ? `${r.hora_inicio.slice(0,5)} a ${r.hora_fin.slice(0,5)}` 
                 : "Horario a confirmar";

    // Manejo de Aula (puede ser objeto o string)
    let aula = "Aula sin asignar";
    if (r.aula) {
        aula = typeof r.aula === 'object' ? (r.aula.nombre || r.aula.descripcion) : r.aula;
    } else if (r.nombre_aula) { // Fallback por si la API usa otro nombre
        aula = r.nombre_aula;
    }

    // Tipo de clase (Teoría, Práctica, Consulta)
    const tipo = r.tipo || r.comision || "Clase";

    return `🕒 **${dia} ${hora}**\n   📍 ${aula} (${tipo})`;
  }).join("\n\n");

  return `📅 HORARIOS Y AULAS CONFIRMADAS PARA ${slug.toUpperCase()}:\n\n${lista}`;

} catch (error) {
  const errorMsg = error.response?.data ? JSON.stringify(error.response.data) : error.message;
  return `ERROR TÉCNICO al consultar reservas: ${errorMsg}`;
}

// 1. OBTENCIÓN Y NORMALIZACIÓN
// Como no tenemos lista de aulas, ayudamos a la IA convirtiendo "Aula 5" -> "aula-5"
let slug = query.slug;

if (!slug) return "ERROR: No llegó el identificador del aula.";

// Normalización técnica: minúsculas y espacios por guiones
const slugFinal = slug.toLowerCase().replace(/\s+/g, '-').trim();

// 2. FECHA DE HOY (Para filtrar y no traer historial viejo)
// Calculamos la fecha actual en formato YYYY-MM-DD para el parámetro 'desde'
const hoy = new Date().toISOString().split('T')[0];

try {
  // 3. LLAMADA A LA API
  // Usamos el filtro 'desde' para ver solo lo futuro/actual
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://gestiondocente.info.unlp.edu.ar/api/v2/aulas/${slugFinal}/reservas.json`,
    qs: { desde: hoy }, 
    json: true
  });

  // 4. ESTRATEGIA DE LECTURA (HATEOAS vs Directo)
  const reservas = response._embedded?.reservas || response || [];

  if (!Array.isArray(reservas) || reservas.length === 0) {
    return `ℹ️ No encontré reservas registradas en el '${slugFinal}' a partir de hoy. Podría estar libre.`;
  }

  // 5. FORMATEO DE SALIDA
  // Ordenamos por día/hora para que quede cronológico
  const lista = reservas
    .slice(0, 10) // Limitamos a 10 eventos para no llenar la pantalla
    .map(r => {
        const dia = r.dia || r.fecha || "Fecha a confirmar";
        const hora = (r.hora_inicio && r.hora_fin) 
                     ? `${r.hora_inicio.slice(0,5)} a ${r.hora_fin.slice(0,5)}` 
                     : "Horario desc.";

        // Intentamos sacar el nombre de la materia o evento
        let evento = "Evento reservado";
        if (r.materia) {
            evento = typeof r.materia === 'object' ? r.materia.nombre : r.materia;
        } else if (r.evento) {
            evento = r.evento;
        }

        return `📍 **${dia} [${hora}]**\n   🎓 ${evento}`;
    }).join("\n\n");

  return `📅 OCUPACIÓN DEL ${slugFinal.toUpperCase()}:\n\n${lista}`;

} catch (error) {
  return `ERROR 404: No pude encontrar el aula '${slugFinal}'. Verifica si el número es correcto (ej: Aula 5, Aula Magna).`;
}

